  1→/**
  2→ * Protocol types for communication between the Rust core and TypeScript frontend.
  3→ *
  4→ * All messages are newline-delimited JSON over stdin/stdout. The core sends
  5→ * Request messages and receives Response messages back. Every message includes
  6→ * a protocol version for compatibility checking.
  7→ */
  8→
  9→export const PROTOCOL_VERSION = "0.1.0";
 10→export const FRONTEND_LANGUAGE = "typescript";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Request: Core → Frontend
 14→// ---------------------------------------------------------------------------
 15→
 16→export type SetupMode = "per_function" | "per_execution";
 17→
 18→export type GeneratorKind = "type_name" | "param_name";
 19→
 20→export type Command =
 21→  | "handshake"
 22→  | "analyze"
 23→  | "instrument"
 24→  | "execute"
 25→  | "setup"
 26→  | "teardown"
 27→  | "generate"
 28→  | "shutdown";
 29→
 30→export interface MockConfig {
 31→  symbol: string;
 32→  return_values: unknown[];
 33→  should_track_calls: boolean;
 34→  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
 35→}
 36→
 37→interface BaseRequest {
 38→  protocol_version: string;
 39→  id: number;
 40→  command: Command;
 41→}
 42→
 43→export interface HandshakeRequest extends BaseRequest {
 44→  command: "handshake";
 45→  capabilities: string[];
 46→}
 47→
 48→export interface AnalyzeRequest extends BaseRequest {
 49→  command: "analyze";
 50→  file: string;
 51→  function?: string | null;
 52→  project_root?: string | null;
 53→}
 54→
 55→export interface InstrumentRequest extends BaseRequest {
 56→  command: "instrument";
 57→  file: string;
 58→  function: string;
 59→  mocks: MockConfig[];
 60→  project_root?: string | null;
 61→}
 62→
 63→export interface ExecuteRequest extends BaseRequest {
 64→  command: "execute";
 65→  function: string;
 66→  inputs: unknown[];
 67→  mocks: MockConfig[];
 68→  setup_context?: unknown;
 69→}
 70→
 71→export interface SetupRequest extends BaseRequest {
 72→  command: "setup";
 73→  file: string;
 74→  function: string;
 75→  mode: SetupMode;
 76→  project_root?: string | null;
 77→}
 78→
 79→export interface TeardownRequest extends BaseRequest {
 80→  command: "teardown";
 81→  function: string;
 82→}
 83→
 84→export interface GenerateRequest extends BaseRequest {
 85→  command: "generate";
 86→  file: string;
 87→  name: string;
 88→  kind: GeneratorKind;
 89→  recipe?: unknown;
 90→  project_root?: string | null;
 91→}
 92→
 93→export interface ShutdownRequest extends BaseRequest {
 94→  command: "shutdown";
 95→}
 96→
 97→export type Request =
 98→  | HandshakeRequest
 99→  | AnalyzeRequest
100→  | InstrumentRequest
101→  | ExecuteRequest
102→  | SetupRequest
103→  | TeardownRequest
104→  | GenerateRequest
105→  | ShutdownRequest;
106→
107→// ---------------------------------------------------------------------------
108→// Response: Frontend → Core
109→// ---------------------------------------------------------------------------
110→
111→export type ResponseStatus =
112→  | "handshake"
113→  | "analyze"
114→  | "instrument"
115→  | "execute"
116→  | "setup"
117→  | "teardown_ack"
118→  | "generate"
119→  | "shutdown_ack"
120→  | "error";
121→
122→export type ErrorCode =
123→  | "file_not_found"
124→  | "function_not_found"
125→  | "parse_error"
126→  | "instrumentation_failed"
127→  | "execution_timeout"
128→  | "execution_crash"
129→  | "version_mismatch"
130→  | "invalid_request"
131→  | "internal_error";
132→
133→interface BaseResponse {
134→  protocol_version: string;
135→  id: number;
136→  status: ResponseStatus;
137→}
138→
139→export interface HandshakeResponse extends BaseResponse {
140→  status: "handshake";
141→  frontend_version: string;
142→  language: string;
143→  capabilities: string[];
144→}
145→
146→export interface AnalyzeResponse extends BaseResponse {
147→  status: "analyze";
148→  functions: FunctionAnalysis[];
149→}
150→
151→export interface InstrumentResponse extends BaseResponse {
152→  status: "instrument";
153→  instrumented: boolean;
154→  output_file: string | null;
155→  instrumentable_line_count?: number;
156→}
157→
158→export interface ExecuteResponse extends BaseResponse {
159→  status: "execute";
160→  return_value: unknown;
161→  thrown_error: ErrorInfo | null;
162→  branch_path: BranchDecision[];
163→  lines_executed: number[];
164→  calls_to_external: ExternalCall[];
165→  path_constraints: SymConstraint[];
166→  side_effects: SideEffect[];
167→  performance: PerformanceMetrics;
168→  capture_truncation?: TruncationInfo;
169→  scope_events?: TraceEvent[];
170→}
171→
172→export interface SetupResponse extends BaseResponse {
173→  status: "setup";
174→  setup_context: unknown;
175→}
176→
177→export interface TeardownAckResponse extends BaseResponse {
178→  status: "teardown_ack";
179→}
180→
181→export interface GenerateResponse extends BaseResponse {
182→  status: "generate";
183→  value: unknown;
184→  generator_id: string;
185→  recipe?: unknown;
186→}
187→
188→export interface ShutdownAckResponse extends BaseResponse {
189→  status: "shutdown_ack";
190→}
191→
192→export interface ErrorResponse extends BaseResponse {
193→  status: "error";
194→  code: ErrorCode;
195→  message: string;
196→  details?: unknown;
197→}
198→
199→export type Response =
200→  | HandshakeResponse
201→  | AnalyzeResponse
202→  | InstrumentResponse
203→  | ExecuteResponse
204→  | SetupResponse
205→  | TeardownAckResponse
206→  | GenerateResponse
207→  | ShutdownAckResponse
208→  | ErrorResponse;
209→
210→// ---------------------------------------------------------------------------
211→// Supporting types
212→// ---------------------------------------------------------------------------
213→
214→/** A literal constant extracted from source code for use as a candidate test input. */
215→export type LiteralValue =
216→  | { type: "int"; value: number }
217→  | { type: "float"; value: number }
218→  | { type: "str"; value: string }
219→  | { type: "bool"; value: boolean }
220→  | { type: "regex"; pattern: string };
221→
222→export interface CryptoBoundary {
223→  symbol: string;
224→  source_module: string;
225→  direction: "encrypt" | "decrypt" | "both";
226→  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
227→  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
228→  call_sites: number[];
229→}
230→
231→export interface FunctionAnalysis {
232→  name: string;
233→  exported?: boolean;
234→  params: ParamInfo[];
235→  branches: BranchInfo[];
236→  dependencies: ExternalDependency[];
237→  return_type: TypeInfo;
238→  start_line: number;
239→  end_line: number;
240→  literals?: LiteralValue[];
241→  crypto_boundaries?: CryptoBoundary[];
242→}
243→
244→export interface ParamInfo {
245→  name: string;
246→  type: TypeInfo;
247→  type_name?: string;
248→}
249→
250→/** Well-known complex types beyond primitives and structural types. */
251→export type ComplexKind =
252→  | "date" | "date_time" | "time" | "duration"
253→  | "reg_exp" | "char" | "symbol"
254→  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
255→  | "buffer" | "bit_set"
256→  | "error" | "option" | "result"
257→  | "closure" | "iterator"
258→  | "url" | "ip_address"
259→  | "uuid"
260→  | "path"
261→  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
262→  | "rune" | "go_byte";
263→
264→export type TypeInfo =
265→  | { kind: "int" }
266→  | { kind: "float" }
267→  | { kind: "str" }
268→  | { kind: "bool" }
269→  | { kind: "unknown" }
270→  | { kind: "array"; element: TypeInfo }
271→  | { kind: "object"; fields: [string, TypeInfo][] }
272→  | { kind: "union"; variants: TypeInfo[] }
273→  | { kind: "nullable"; inner: TypeInfo }
274→  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
275→  | { kind: "opaque"; label: string };
276→
277→export interface BranchInfo {
278→  id: number;
279→  line: number;
280→  condition_text: string;
281→  condition: SymExpr | null;
282→  branch_type: BranchType;
283→}
284→
285→export type BranchType =
286→  | "if"
287→  | "else_if"
288→  | "switch"
289→  | "ternary"
290→  | "logical_and"
291→  | "logical_or"
292→  | "while"
293→  | "for";
294→
295→export type SymExpr =
296→  | { kind: "param"; name: string; path: string[] }
297→  | SymExprConst
298→  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
299→  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
300→  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
301→  | { kind: "unknown" };
302→
303→/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
304→export type SymExprConst =
305→  | { kind: "const"; type: "int"; value: number }
306→  | { kind: "const"; type: "float"; value: number }
307→  | { kind: "const"; type: "str"; value: string }
308→  | { kind: "const"; type: "bool"; value: boolean }
309→  | { kind: "const"; type: "null" }
310→  | { kind: "const"; type: "undefined" }
311→  | { kind: "const"; type: "complex"; value: { kind: ComplexKind; repr: SymExprConst } };
312→
313→export type BinOpKind =
314→  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
315→  | "add" | "sub" | "mul" | "div" | "mod"
316→  | "and" | "or"
317→  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
318→  | "in" | "instance_of";
319→
320→export type UnOpKind = "not" | "neg" | "bitwise_not" | "typeof";
321→
322→export interface BranchDecision {
323→  branch_id: number;
324→  line: number;
325→  taken: boolean;
326→  constraint: SymConstraint;
327→}
328→
329→export type ScopeEvent =
330→  | { kind: "loop_enter"; loop_id: number }
331→  | { kind: "loop_exit"; loop_id: number }
332→  | { kind: "call_enter"; call_site_id: number }
333→  | { kind: "call_exit"; call_site_id: number };
334→
335→export type TraceEvent =
336→  | { type: "branch"; decision: BranchDecision }
337→  | { type: "scope"; event: ScopeEvent };
338→
339→export type SymConstraint =
340→  | { kind: "expr"; expr: SymExpr }
341→  | { kind: "unknown"; hint: string };
342→
343→export interface ExternalCall {
344→  symbol: string;
345→  args: unknown[];
346→  return_value: unknown;
347→}
348→
349→export interface ExternalDependency {
350→  kind: DependencyKind;
351→  symbol: string;
352→  source_module: string;
353→  return_type: TypeInfo;
354→  param_types: TypeInfo[];
355→  call_sites: number[];
356→}
357→
358→export type DependencyKind =
359→  | "function_call"
360→  | "method_call"
361→  | "property_access"
362→  | "module_import";
363→
364→export type SideEffect =
365→  | { kind: "console_output"; level: string; message: string }
366→  | { kind: "file_write"; path: string; content: string }
367→  | { kind: "network_request"; method: string; url: string; body: unknown }
368→  | { kind: "environment_read"; variable: string; value: string | null }
369→  | { kind: "global_mutation"; name: string }
370→  | { kind: "thrown_error"; error_type: string; message: string; stack: string | null }
371→  | { kind: "global_state_change"; variable: string; before: unknown; after: unknown };
372→
373→export type ErrorCategory = "validation" | "runtime" | "infrastructure" | "unknown";
374→
375→export interface ErrorInfo {
376→  error_type: string;
377→  message: string;
378→  stack: string | null;
379→  error_category?: ErrorCategory;
380→}
381→
382→export interface TruncationInfo {
383→  was_truncated: boolean;
384→  original_lines: number;
385→  original_bytes: number;
386→}
387→
388→export interface PerformanceMetrics {
389→  wall_time_ms: number;
390→  cpu_time_us: number;
391→  heap_used_bytes: number;
392→  heap_allocated_bytes: number;
393→}
394→

 1→#!/usr/bin/env node
 2→
 3→/**
 4→ * Shatter TypeScript frontend entry point.
 5→ *
 6→ * Reads newline-delimited JSON protocol messages from stdin and writes
 7→ * responses to stdout. Debug output goes to stderr.
 8→ */
 9→
10→import * as readline from "node:readline";
11→import { handleRequest, parseRequest } from "./handlers.js";
12→import logger from "./logger.js";
13→import { PROTOCOL_VERSION, type Response } from "./protocol.js";
14→
15→function sendResponse(response: Response): void {
16→  const json = JSON.stringify(response);
17→  process.stdout.write(json + "\n");
18→  logger.trace({ raw: json }, "Sent");
19→}
20→
21→function main(): void {
22→  logger.debug("Starting TypeScript frontend (protocol 0.1.0)");
23→
24→  const rl = readline.createInterface({
25→    input: process.stdin,
26→    terminal: false,
27→  });
28→
29→  rl.on("line", (line: string) => {
30→    const trimmed = line.trim();
31→    if (trimmed === "") return;
32→
33→    logger.trace({ raw: trimmed }, "Received");
34→
35→    const result = parseRequest(trimmed);
36→
37→    if ("error" in result) {
38→      sendResponse(result.error);
39→      return;
40→    }
41→
42→    const requestId = result.request.id;
43→    void handleRequest(result.request).then(({ response, shutdown }) => {
44→      sendResponse(response);
45→
46→      if (shutdown) {
47→        logger.debug("Shutting down");
48→        rl.close();
49→      }
50→    }).catch((err: unknown) => {
51→      const msg = err instanceof Error ? err.message : String(err);
52→      logger.error("Unhandled error processing request %s: %s", requestId, msg);
53→      sendResponse({
54→        protocol_version: PROTOCOL_VERSION,
55→        id: requestId,
56→        status: "error",
57→        code: "internal_error",
58→        message: `Unhandled error: ${msg}`,
59→      } as Response);
60→    });
61→  });
62→
63→  rl.on("close", () => {
64→    logger.debug("Stdin closed, exiting");
65→    process.exit(0);
66→  });
67→}
68→
69→main();
70→

  1→/**
  2→ * Command handlers for the Shatter protocol.
  3→ *
  4→ * Each handler receives a typed request and returns a typed response.
  5→ * The instrument handler stores instrumented source in memory so the
  6→ * execute handler can use it for branch-recording execution.
  7→ */
  8→
  9→import * as fs from "node:fs";
 10→import * as path from "node:path";
 11→import {
 12→  PROTOCOL_VERSION,
 13→  FRONTEND_LANGUAGE,
 14→  type Request,
 15→  type Response,
 16→  type ErrorResponse,
 17→} from "./protocol.js";
 18→import { analyzeFile } from "./analyzer.js";
 19→import { instrumentFunction } from "./instrumentor.js";
 20→import {
 21→  executeFunction,
 22→  executeInstrumented,
 23→  buildExecuteResponse,
 24→  setProjectRoot,
 25→  clearModuleCache,
 26→} from "./executor.js";
 27→import {
 28→  loadSetupModule,
 29→  runSetup,
 30→  runTeardown,
 31→  loadGeneratorModule,
 32→  runGenerator,
 33→  type SetupModule,
 34→} from "./setup-loader.js";
 35→import {
 36→  loadWasmPlugin,
 37→  runWasmGenerator,
 38→  clearWasmCache,
 39→} from "./wasm-generator.js";
 40→
 41→/** Supported capabilities for this frontend. */
 42→const SUPPORTED_CAPABILITIES = [
 43→  "analyze", "execute", "instrument", "setup", "generate",
 44→  "complex_type:date", "complex_type:date_time", "complex_type:duration",
 45→  "complex_type:reg_exp", "complex_type:url", "complex_type:big_int",
 46→  "complex_type:buffer", "complex_type:error", "complex_type:symbol",
 47→];
 48→
 49→/** Track the last analyzed file so execute can resolve function references. */
 50→let lastAnalyzedFile: string | null = null;
 51→
 52→/**
 53→ * Stored instrumented sources, keyed by "file:function".
 54→ * Set by the instrument handler, consumed by the execute handler.
 55→ */
 56→const instrumentedSources = new Map<string, string>();
 57→
 58→/**
 59→ * Loaded setup modules, keyed by file path.
 60→ * Cached so teardown can use the same module instance as setup.
 61→ */
 62→const loadedSetupModules = new Map<string, SetupModule>();
 63→
 64→/**
 65→ * Setup contexts from the most recent setup call, keyed by function name.
 66→ * Stored so teardown can pass the context back to the teardown function.
 67→ */
 68→const setupContexts = new Map<string, { module: SetupModule; context: unknown }>();
 69→
 70→/**
 71→ * Dispatch a parsed request to the appropriate handler.
 72→ *
 73→ * Returns a Response and a shutdown flag. The handler is async because
 74→ * WASM generator loading requires awaiting plugin creation.
 75→ */
 76→export async function handleRequest(request: Request): Promise<{ response: Response; shutdown: boolean }> {
 77→  if (!isVersionCompatible(request.protocol_version)) {
 78→    return {
 79→      response: errorResponse(request.id, "version_mismatch",
 80→        `Unsupported protocol version: ${request.protocol_version} (expected ${PROTOCOL_VERSION})`),
 81→      shutdown: false,
 82→    };
 83→  }
 84→
 85→  switch (request.command) {
 86→    case "handshake":
 87→      return {
 88→        response: {
 89→          protocol_version: PROTOCOL_VERSION,
 90→          id: request.id,
 91→          status: "handshake",
 92→          frontend_version: PROTOCOL_VERSION,
 93→          language: FRONTEND_LANGUAGE,
 94→          capabilities: SUPPORTED_CAPABILITIES,
 95→        },
 96→        shutdown: false,
 97→      };
 98→
 99→    case "analyze": {
100→      if (!fs.existsSync(request.file)) {
101→        return {
102→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
103→          shutdown: false,
104→        };
105→      }
106→
107→      lastAnalyzedFile = path.resolve(request.file);
108→      setProjectRoot(request.project_root);
109→      const functions = analyzeFile(request.file, request.function, request.project_root);
110→
111→      if (request.function != null && functions.length === 0) {
112→        return {
113→          response: errorResponse(
114→            request.id,
115→            "function_not_found",
116→            `Function not found: ${request.function} in ${request.file}`,
117→          ),
118→          shutdown: false,
119→        };
120→      }
121→
122→      return {
123→        response: {
124→          protocol_version: PROTOCOL_VERSION,
125→          id: request.id,
126→          status: "analyze",
127→          functions,
128→        },
129→        shutdown: false,
130→      };
131→    }
132→
133→    case "instrument": {
134→      if (!fs.existsSync(request.file)) {
135→        return {
136→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
137→          shutdown: false,
138→        };
139→      }
140→
141→      const source = fs.readFileSync(request.file, "utf-8");
142→      const result = instrumentFunction(source, request.function, request.file);
143→
144→      if ("error" in result) {
145→        return {
146→          response: errorResponse(request.id, "instrumentation_failed", result.error),
147→          shutdown: false,
148→        };
149→      }
150→
151→      // Store the instrumented source for use by the execute handler.
152→      // Use resolved path so keys match execute's resolved fileForExec.
153→      const key = `${path.resolve(request.file)}:${request.function}`;
154→      instrumentedSources.set(key, result.instrumentedSource);
155→      lastAnalyzedFile = path.resolve(request.file);
156→
157→      return {
158→        response: {
159→          protocol_version: PROTOCOL_VERSION,
160→          id: request.id,
161→          status: "instrument",
162→          instrumented: true,
163→          output_file: null,
164→          instrumentable_line_count: result.instrumentableLineCount,
165→        },
166→        shutdown: false,
167→      };
168→    }
169→
170→    case "execute": {
171→      const funcRef = request.function;
172→      const fileForExec = resolveFileForExecute(funcRef);
173→
174→      if (!fileForExec) {
175→        return {
176→          response: errorResponse(
177→            request.id,
178→            "function_not_found",
179→            `Cannot resolve file for function: ${funcRef}. Use file:function format.`,
180→          ),
181→          shutdown: false,
182→        };
183→      }
184→
185→      try {
186→        // Check if we have instrumented source for this function
187→        const funcName = funcRef.includes(":") ? funcRef.split(":").pop()! : funcRef;
188→        const instrumentKey = `${fileForExec}:${funcName}`;
189→        const instrumentedSource = instrumentedSources.get(instrumentKey);
190→
191→        let rawResult;
192→        if (instrumentedSource) {
193→          rawResult = await executeInstrumented(instrumentedSource, funcName, request.inputs, request.mocks ?? [], fileForExec);
194→        } else {
195→          rawResult = await executeFunction(fileForExec, funcRef, request.inputs);
196→        }
197→
198→        return {
199→          response: buildExecuteResponse(request.id, PROTOCOL_VERSION, rawResult),
200→          shutdown: false,
201→        };
202→      } catch (e: unknown) {
203→        const msg = e instanceof Error ? e.message : String(e);
204→        return {
205→          response: errorResponse(request.id, "internal_error", `Execute failed: ${msg}`),
206→          shutdown: false,
207→        };
208→      }
209→    }
210→
211→    case "setup": {
212→      if (!fs.existsSync(request.file)) {
213→        return {
214→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
215→          shutdown: false,
216→        };
217→      }
218→
219→      try {
220→        let setupModule = loadedSetupModules.get(request.file);
221→        if (!setupModule) {
222→          setupModule = loadSetupModule(request.file);
223→          loadedSetupModules.set(request.file, setupModule);
224→        }
225→
226→        const setupContext = runSetup(setupModule, request.function, request.mode);
227→        setupContexts.set(request.function, { module: setupModule, context: setupContext });
228→
229→        return {
230→          response: {
231→            protocol_version: PROTOCOL_VERSION,
232→            id: request.id,
233→            status: "setup",
234→            setup_context: setupContext,
235→          },
236→          shutdown: false,
237→        };
238→      } catch (e: unknown) {
239→        const msg = e instanceof Error ? e.message : String(e);
240→        return {
241→          response: errorResponse(request.id, "internal_error", `Setup failed: ${msg}`),
242→          shutdown: false,
243→        };
244→      }
245→    }
246→
247→    case "teardown": {
248→      try {
249→        const stored = setupContexts.get(request.function);
250→        if (!stored) {
251→          return {
252→            response: errorResponse(
253→              request.id,
254→              "internal_error",
255→              `No setup context found for function: ${request.function}. Call setup first.`,
256→            ),
257→            shutdown: false,
258→          };
259→        }
260→
261→        runTeardown(stored.module, request.function, stored.context);
262→        setupContexts.delete(request.function);
263→        instrumentedSources.clear();
264→        clearModuleCache();
265→
266→        return {
267→          response: {
268→            protocol_version: PROTOCOL_VERSION,
269→            id: request.id,
270→            status: "teardown_ack",
271→          },
272→          shutdown: false,
273→        };
274→      } catch (e: unknown) {
275→        const msg = e instanceof Error ? e.message : String(e);
276→        return {
277→          response: errorResponse(request.id, "internal_error", `Teardown failed: ${msg}`),
278→          shutdown: false,
279→        };
280→      }
281→    }
282→
283→    case "generate": {
284→      if (!fs.existsSync(request.file)) {
285→        return {
286→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
287→          shutdown: false,
288→        };
289→      }
290→
291→      try {
292→        if (request.file.endsWith(".wasm")) {
293→          const plugin = await loadWasmPlugin(request.file);
294→          const result = await runWasmGenerator(plugin, request.name, request.recipe);
295→
296→          return {
297→            response: {
298→              protocol_version: PROTOCOL_VERSION,
299→              id: request.id,
300→              status: "generate",
301→              value: result.value,
302→              generator_id: result.id,
303→              ...(result.recipe !== undefined ? { recipe: result.recipe } : {}),
304→            },
305→            shutdown: false,
306→          };
307→        }
308→
309→        const generatorModule = loadGeneratorModule(request.file);
310→        const value = runGenerator(generatorModule, request.name, request.kind);
311→
312→        return {
313→          response: {
314→            protocol_version: PROTOCOL_VERSION,
315→            id: request.id,
316→            status: "generate",
317→            value,
318→            generator_id: "generated",
319→          },
320→          shutdown: false,
321→        };
322→      } catch (e: unknown) {
323→        const msg = e instanceof Error ? e.message : String(e);
324→        return {
325→          response: errorResponse(request.id, "internal_error", `Generate failed: ${msg}`),
326→          shutdown: false,
327→        };
328→      }
329→    }
330→
331→    case "shutdown":
332→      await clearWasmCache();
333→      instrumentedSources.clear();
334→      clearModuleCache();
335→      return {
336→        response: {
337→          protocol_version: PROTOCOL_VERSION,
338→          id: request.id,
339→          status: "shutdown_ack",
340→        },
341→        shutdown: true,
342→      };
343→  }
344→}
