  1→/**
  2→ * Setup and generator module loader for the Shatter TypeScript frontend.
  3→ *
  4→ * Loads user-provided setup/teardown and generator files using the same
  5→ * vm.createContext + TypeScript transpile pattern as executor.ts.
  6→ */
  7→
  8→import * as ts from "typescript";
  9→import * as fs from "node:fs";
 10→import * as vm from "node:vm";
 11→import * as path from "node:path";
 12→import { createRequire } from "node:module";
 13→import type { SetupMode, GeneratorKind } from "./protocol.js";
 14→
 15→/** A loaded setup module with its exports available for calling. */
 16→export interface SetupModule {
 17→  exports: Record<string, unknown>;
 18→  filePath: string;
 19→}
 20→
 21→/** A loaded generator module with its exports available for calling. */
 22→export interface GeneratorModule {
 23→  exports: Record<string, unknown>;
 24→  filePath: string;
 25→}
 26→
 27→/**
 28→ * Transpile and load a TypeScript/JavaScript file, returning its exports.
 29→ */
 30→function loadAndTranspile(filePath: string): Record<string, unknown> {
 31→  const absolutePath = path.resolve(filePath);
 32→  const source = fs.readFileSync(absolutePath, "utf-8");
 33→  const result = ts.transpileModule(source, {
 34→    compilerOptions: {
 35→      target: ts.ScriptTarget.ES2022,
 36→      module: ts.ModuleKind.CommonJS,
 37→      esModuleInterop: true,
 38→      strict: true,
 39→      jsx: ts.JsxEmit.ReactJSX,
 40→    },
 41→    fileName: absolutePath,
 42→  });
 43→
 44→  const targetRequire = createRequire(absolutePath);
 45→  const moduleExports: Record<string, unknown> = {};
 46→  const moduleObj = { exports: moduleExports };
 47→
 48→  const sandbox = vm.createContext({
 49→    module: moduleObj,
 50→    exports: moduleExports,
 51→    require: targetRequire,
 52→    console,
 53→    process,
 54→    Buffer,
 55→    setTimeout,
 56→    clearTimeout,
 57→    setInterval,
 58→    clearInterval,
 59→    __filename: absolutePath,
 60→    __dirname: path.dirname(absolutePath),
 61→  });
 62→
 63→  vm.runInContext(result.outputText, sandbox, { filename: absolutePath });
 64→
 65→  const finalExports = (sandbox as Record<string, unknown>)["module"] as {
 66→    exports: Record<string, unknown>;
 67→  };
 68→  return finalExports.exports;
 69→}
 70→
 71→/**
 72→ * Load a setup module file. The file should export a `setup()` function
 73→ * and optionally a `teardown()` function.
 74→ */
 75→export function loadSetupModule(file: string): SetupModule {
 76→  const exports = loadAndTranspile(file);
 77→  return { exports, filePath: path.resolve(file) };
 78→}
 79→
 80→/**
 81→ * Run the setup() export from a loaded setup module.
 82→ *
 83→ * Calls `module.setup(functionName, mode)` and returns the setup_context.
 84→ */
 85→export function runSetup(
 86→  setupModule: SetupModule,
 87→  functionName: string,
 88→  mode: SetupMode,
 89→): unknown {
 90→  const setupFn = setupModule.exports["setup"];
 91→  if (typeof setupFn !== "function") {
 92→    throw new Error(
 93→      `Setup file "${setupModule.filePath}" does not export a setup() function. ` +
 94→      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
 95→    );
 96→  }
 97→  return (setupFn as (fn: string, mode: string) => unknown)(functionName, mode);
 98→}
 99→
100→/**
101→ * Run the teardown() export from a loaded setup module.
102→ *
103→ * Calls `module.teardown(functionName, setupContext)`.
104→ */
105→export function runTeardown(
106→  setupModule: SetupModule,
107→  functionName: string,
108→  setupContext: unknown,
109→): void {
110→  const teardownFn = setupModule.exports["teardown"];
111→  if (typeof teardownFn !== "function") {
112→    throw new Error(
113→      `Setup file "${setupModule.filePath}" does not export a teardown() function. ` +
114→      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
115→    );
116→  }
117→  (teardownFn as (fn: string, ctx: unknown) => void)(functionName, setupContext);
118→}
119→
120→/**
121→ * Load a generator module file. The file should export named functions
122→ * that produce values when called.
123→ */
124→export function loadGeneratorModule(file: string): GeneratorModule {
125→  const exports = loadAndTranspile(file);
126→  return { exports, filePath: path.resolve(file) };
127→}
128→
129→/**
130→ * Run a named generator function from a loaded generator module.
131→ *
132→ * For `kind: "type_name"`, `name` is the type name (e.g. "User").
133→ * For `kind: "param_name"`, `name` is the parameter name (e.g. "authToken").
134→ *
135→ * The module should export a function with that name.
136→ */
137→export function runGenerator(
138→  generatorModule: GeneratorModule,
139→  name: string,
140→  kind: GeneratorKind,
141→): unknown {
142→  const genFn = generatorModule.exports[name];
143→  if (typeof genFn !== "function") {
144→    throw new Error(
145→      `Generator file "${generatorModule.filePath}" does not export a "${name}" function ` +
146→      `(kind: ${kind}). Available exports: ${Object.keys(generatorModule.exports).join(", ")}`,
147→    );
148→  }
149→  return (genFn as () => unknown)();
150→}
