  7→import fc from "fast-check";
  8→import ts from "typescript";
  9→import type {
 10→  BinOpKind,
 11→  UnOpKind,
 12→  SymExpr,
 13→  SymExprConst,
 14→  TypeInfo,
 15→  ComplexKind,
 16→  BranchType,
 17→  BranchDecision,
 18→  SymConstraint,
 19→  ErrorCode,
 20→  SideEffect,
 21→  PerformanceMetrics,
 22→  TraceEvent,
 23→  ScopeEvent,
 24→  HandshakeRequest,
 25→  AnalyzeRequest,
 26→  ExecuteRequest,
 27→  ShutdownRequest,
 28→  Request,
 29→  HandshakeResponse,
 30→  AnalyzeResponse,
 31→  ErrorResponse,
 32→  Response,
 33→  FunctionAnalysis,
 34→  ParamInfo,
