 39→import { buildSymExpr, buildSymExprWithFlow } from "./instrumentor.js";
 40→
 41→// ---------------------------------------------------------------------------
 42→// Arbitraries — leaf types
 43→// ---------------------------------------------------------------------------
 44→
 45→const arbIdent = fc.stringMatching(/^[a-zA-Z_][a-zA-Z0-9_]{0,12}$/);
 46→const arbShortString = fc.string({ maxLength: 30 });
 47→
 48→const arbBinOpKind: fc.Arbitrary<BinOpKind> = fc.constantFrom(
 49→  "eq", "ne", "lt", "le", "gt", "ge",
 50→  "add", "sub", "mul", "div", "mod",
 51→  "and", "or",
 52→  "bitwise_and", "bitwise_or", "bitwise_xor",
 53→  "in", "instance_of",
 54→);
