 57→  "not", "neg", "bitwise_not", "typeof",
 58→);
 59→
 60→const arbComplexKind: fc.Arbitrary<ComplexKind> = fc.constantFrom(
 61→  "date", "date_time", "time", "duration",
 62→  "reg_exp", "char", "symbol",
 63→  "big_int", "big_decimal", "complex", "rational", "range",
 64→  "buffer", "bit_set",
 65→  "error", "option", "result",
 66→  "closure", "iterator",
 67→  "url", "ip_address",
 68→  "uuid", "path",
 69→  "money", "sem_ver", "email", "mime_type", "color", "geo_point", "locale",
 70→  "rune", "go_byte",
 71→);
 72→
 73→const arbBranchType: fc.Arbitrary<BranchType> = fc.constantFrom(
 74→  "if", "else_if", "switch", "ternary",
