 84→// ---------------------------------------------------------------------------
 85→// Arbitraries — recursive types
 86→// ---------------------------------------------------------------------------
 87→
 88→const arbSymExprConst: fc.Arbitrary<SymExprConst> = fc.oneof(
 89→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("int" as const), value: fc.integer({ min: -10000, max: 10000 }) }),
 90→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("float" as const), value: fc.integer({ min: -1000, max: 1000 }) }),
 91→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("str" as const), value: arbShortString }),
 92→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("bool" as const), value: fc.boolean() }),
 93→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("null" as const) }),
 94→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("undefined" as const) }),
 95→);
 96→
 97→const arbSymExpr: fc.Arbitrary<SymExpr> = fc.letrec<{ expr: SymExpr }>(tie => ({
 98→  expr: fc.oneof(
 99→    { depthIdentifier: "symexpr", maxDepth: 3 },
100→    fc.record({
101→      kind: fc.constant("param" as const),
102→      name: arbIdent,
103→      path: fc.array(arbIdent, { maxLength: 3 }),
104→    }),
105→    arbSymExprConst,
106→    fc.record({ kind: fc.constant("unknown" as const) }),
107→    fc.record({
108→      kind: fc.constant("bin_op" as const),
109→      op: arbBinOpKind,
110→      left: tie("expr"),
111→      right: tie("expr"),
112→    }),
113→    fc.record({
114→      kind: fc.constant("un_op" as const),
115→      op: arbUnOpKind,
116→      operand: tie("expr"),
117→    }),
118→  ),
119→})).expr;
120→
121→const arbTypeInfoLeaf: fc.Arbitrary<TypeInfo> = fc.oneof(
122→  fc.record({ kind: fc.constant("int" as const) }),
123→  fc.record({ kind: fc.constant("float" as const) }),
124→  fc.record({ kind: fc.constant("str" as const) }),
125→  fc.record({ kind: fc.constant("bool" as const) }),
126→  fc.record({ kind: fc.constant("unknown" as const) }),
127→  fc.record({ kind: fc.constant("opaque" as const), label: arbIdent }),
128→);
129→
130→const arbTypeInfo: fc.Arbitrary<TypeInfo> = fc.letrec<{ ti: TypeInfo }>(tie => ({
131→  ti: fc.oneof(
132→    { depthIdentifier: "typeinfo", maxDepth: 2 },
133→    arbTypeInfoLeaf,
134→    fc.record({ kind: fc.constant("array" as const), element: tie("ti") }),
