413→/**
414→ * Parse a TS expression string and extract the expression AST node.
415→ * Wraps the expression in `const __expr = EXPR;` so the compiler parses it.
416→ */
417→function parseExpr(exprSource: string): ts.Expression {
418→  const source = `const __expr = ${exprSource};`;
419→  const sf = ts.createSourceFile("test.ts", source, ts.ScriptTarget.ESNext, true);
420→  const stmt = sf.statements[0] as ts.VariableStatement;
421→  const decl = stmt.declarationList.declarations[0]!;
422→  return decl.initializer!;
423→}
424→
425→/**
426→ * Check if a SymExpr tree contains at least one non-unknown leaf.
427→ * When all leaves are unknown, buildSymExprWithFlow intentionally returns
428→ * unknown as an optimization — this is not a parity violation.
429→ */
430→function hasNonUnknownLeaf(expr: SymExpr): boolean {
431→  if (expr.kind === "param" || expr.kind === "const") return true;
432→  if (expr.kind === "bin_op") return hasNonUnknownLeaf(expr.left) || hasNonUnknownLeaf(expr.right);
433→  if (expr.kind === "un_op") return hasNonUnknownLeaf(expr.operand);
434→  if (expr.kind === "call") {
435→    const recOk = expr.receiver ? hasNonUnknownLeaf(expr.receiver) : false;
436→    return recOk || expr.args.some(hasNonUnknownLeaf);
437→  }
438→  return false;
439→}
440→
441→const PARAM_NAME = "x";
442→const paramNames = new Set([PARAM_NAME]);
443→const resolveName = (name: string): SymExpr | undefined =>
444→  name === PARAM_NAME ? { kind: "param", name: PARAM_NAME, path: [] } : undefined;
445→
446→/** Generator for binary operator source tokens that binaryTokenToOp handles. */
447→const arbBinOp = fc.constantFrom(
448→  "===", "!==", "==", "!=",
449→  "<", "<=", ">", ">=",
450→  "+", "-", "*", "/", "%",
451→  "&&", "||",
452→  "&", "|", "^",
453→);
454→
455→/** Generator for unary prefix operator source tokens. */
456→const arbUnOp = fc.constantFrom("!", "-", "~");
457→
458→/**
459→ * Generator for TypeScript expression source code involving param `x`.
460→ * Each generated expression should be parseable and involve the param
461→ * so at least one builder returns a non-unknown result.
462→ */
463→const arbExprSource: fc.Arbitrary<string> = fc.letrec<{ expr: string }>(tie => ({
464→  expr: fc.oneof(
465→    { depthIdentifier: "exprdepth", maxDepth: 2 },
466→    // Param identifier
467→    fc.constant(PARAM_NAME),
468→    // Numeric literals
469→    fc.integer({ min: -1000, max: 1000 }).map(n => String(n < 0 ? `(${n})` : n)),
470→    // String literals
471→    fc.stringMatching(/^[a-z]{0,5}$/).map(s => `"${s}"`),
472→    // Boolean literals
473→    fc.boolean().map(b => String(b)),
474→    // null
475→    fc.constant("null"),
476→    // Property access on param
477→    fc.stringMatching(/^[a-z]{1,5}$/).map(prop => `${PARAM_NAME}.${prop}`),
478→    // Binary expression with param
479→    arbBinOp.chain(op =>
480→      tie("expr").map(right => `(${PARAM_NAME} ${op} ${right})`),
481→    ),
482→    // Unary prefix
483→    arbUnOp.map(op => `(${op}${PARAM_NAME})`),
484→    // typeof
485→    fc.constant(`(typeof ${PARAM_NAME})`),
486→    // Method call on param
487→    fc.stringMatching(/^[a-z]{1,5}$/).map(m => `${PARAM_NAME}.${m}()`),
488→    // Method call with argument
489→    fc.tuple(
490→      fc.stringMatching(/^[a-z]{1,5}$/),
491→      fc.stringMatching(/^[a-z]{0,3}$/),
492→    ).map(([m, arg]) => `${PARAM_NAME}.${m}("${arg}")`),
493→    // Free function call with param arg
494→    fc.stringMatching(/^[a-z]{1,5}$/).map(fn => `${fn}(${PARAM_NAME})`),
495→  ),
496→})).expr;
