/**
 * Test fixture: a setup module that exports setup() and teardown().
 *
 * setup(scope, parentContext?) returns a context object; teardown(scope, context) cleans up.
 */

export function setup(scope: string, parentContext?: { contexts: Array<{ level: string; context: unknown }> }): { db: string; scope: string; parentLevels: string[] } {
  const parentLevels = parentContext ? parentContext.contexts.map(e => e.level) : [];
  return { db: "test_db_conn", scope, parentLevels };
}

export function teardown(scope: string, context: unknown): void {
  // In a real module this would close connections, delete temp files, etc.
  const ctx = context as { db: string };
  if (!ctx.db) {
    throw new Error("Missing db in context");
  }
}

