413→/**
414→ * Parse a TS expression string and extract the expression AST node.
415→ * Wraps the expression in `const __expr = EXPR;` so the compiler parses it.
416→ */
417→function parseExpr(exprSource: string): ts.Expression {
418→  const source = `const __expr = ${exprSource};`;
419→  const sf = ts.createSourceFile("test.ts", source, ts.ScriptTarget.ESNext, true);
420→  const stmt = sf.statements[0] as ts.VariableStatement;
421→  const decl = stmt.declarationList.declarations[0]!;
422→  return decl.initializer!;
423→}
424→
425→/**
426→ * Check if a SymExpr tree contains at least one non-unknown leaf.
427→ * When all leaves are unknown, buildSymExprWithFlow intentionally returns
428→ * unknown as an optimization — this is not a parity violation.
429→ */
430→function hasNonUnknownLeaf(expr: SymExpr): boolean {
431→  if (expr.kind === "param" || expr.kind === "const") return true;
432→  if (expr.kind === "bin_op") return hasNonUnknownLeaf(expr.left) || hasNonUnknownLeaf(expr.right);
433→  if (expr.kind === "un_op") return hasNonUnknownLeaf(expr.operand);
434→  if (expr.kind === "call") {
435→    const recOk = expr.receiver ? hasNonUnknownLeaf(expr.receiver) : false;
436→    return recOk || expr.args.some(hasNonUnknownLeaf);
437→  }
438→  return false;
439→}
440→
441→const PARAM_NAME = "x";
442→const paramNames = new Set([PARAM_NAME]);
443→const resolveName = (name: string): SymExpr | undefined =>
444→  name === PARAM_NAME ? { kind: "param", name: PARAM_NAME, path: [] } : undefined;
445→
446→/** Generator for binary operator source tokens that binaryTokenToOp handles. */
447→const arbBinOp = fc.constantFrom(
448→  "===", "!==", "==", "!=",
449→  "<", "<=", ">", ">=",
450→  "+", "-", "*", "/", "%",
451→  "&&", "||",
452→  "&", "|", "^",
453→);
454→
455→/** Generator for unary prefix operator source tokens. */
456→const arbUnOp = fc.constantFrom("!", "-", "~");
457→
458→/**
459→ * Generator for TypeScript expression source code involving param `x`.
460→ * Each generated expression should be parseable and involve the param
461→ * so at least one builder returns a non-unknown result.
462→ */
463→const arbExprSource: fc.Arbitrary<string> = fc.letrec<{ expr: string }>(tie => ({
464→  expr: fc.oneof(
465→    { depthIdentifier: "exprdepth", maxDepth: 2 },
466→    // Param identifier
467→    fc.constant(PARAM_NAME),
468→    // Numeric literals
469→    fc.integer({ min: -1000, max: 1000 }).map(n => String(n < 0 ? `(${n})` : n)),
470→    // String literals
471→    fc.stringMatching(/^[a-z]{0,5}$/).map(s => `"${s}"`),
472→    // Boolean literals
473→    fc.boolean().map(b => String(b)),
474→    // null
475→    fc.constant("null"),
476→    // Property access on param
477→    fc.stringMatching(/^[a-z]{1,5}$/).map(prop => `${PARAM_NAME}.${prop}`),
478→    // Binary expression with param
479→    arbBinOp.chain(op =>
480→      tie("expr").map(right => `(${PARAM_NAME} ${op} ${right})`),
481→    ),
482→    // Unary prefix
483→    arbUnOp.map(op => `(${op}${PARAM_NAME})`),
484→    // typeof
485→    fc.constant(`(typeof ${PARAM_NAME})`),
486→    // Method call on param
487→    fc.stringMatching(/^[a-z]{1,5}$/).map(m => `${PARAM_NAME}.${m}()`),
488→    // Method call with argument
489→    fc.tuple(
490→      fc.stringMatching(/^[a-z]{1,5}$/),
491→      fc.stringMatching(/^[a-z]{0,3}$/),
492→    ).map(([m, arg]) => `${PARAM_NAME}.${m}("${arg}")`),
493→    // Free function call with param arg
494→    fc.stringMatching(/^[a-z]{1,5}$/).map(fn => `${fn}(${PARAM_NAME})`),
495→  ),
496→})).expr;
497→
498→describe("property: buildSymExpr / buildSymExprWithFlow parity", () => {
499→  it("both builders handle param-involving expressions consistently", () => {
500→    fc.assert(
501→      fc.property(arbExprSource, (source) => {
502→        let node: ts.Expression;
503→        try {
504→          node = parseExpr(source);
505→        } catch {
506→          return; // skip unparseable expressions
507→        }
508→
509→        const fromBuildSymExpr = buildSymExpr(node, paramNames);
510→        const fromBuildWithFlow = buildSymExprWithFlow(node, resolveName);
511→
512→        const exprResult = fromBuildSymExpr.kind !== "unknown";
513→        const flowResult = fromBuildWithFlow.kind !== "unknown";
514→
515→        // If buildSymExpr returns non-unknown, buildSymExprWithFlow should too
516→        // UNLESS the result has no non-unknown leaves (the "all-unknown
517→        // optimization" in buildSymExprWithFlow is intentional).
518→        if (exprResult && !flowResult) {
519→          expect(hasNonUnknownLeaf(fromBuildSymExpr)).toBe(false);
520→        }
521→
522→        // If buildSymExprWithFlow returns non-unknown, buildSymExpr must too.
523→        // There is no case where flow handles something that expr doesn't.
524→        if (flowResult) {
525→          expect(exprResult).toBe(true);
526→        }
527→      }),
528→      { numRuns: 500 },
529→    );
530→  });
531→
532→  it("individual AST node types are handled by both builders", () => {
533→    // Fixed test cases for each AST node type — these are deterministic
534→    // regression anchors complementing the random property above.
535→    const cases: Array<{ label: string; source: string }> = [
536→      { label: "Identifier (param)", source: "x" },
537→      { label: "NumericLiteral (int)", source: "42" },
538→      { label: "NumericLiteral (float)", source: "3.14" },
539→      { label: "StringLiteral", source: '"hello"' },
540→      { label: "TrueKeyword", source: "true" },
541→      { label: "FalseKeyword", source: "false" },
542→      { label: "NullKeyword", source: "null" },
543→      { label: "BinaryExpression (eq)", source: "x === 1" },
544→      { label: "BinaryExpression (add)", source: "x + 1" },
545→      { label: "BinaryExpression (and)", source: "x && true" },
546→      { label: "PrefixUnaryExpression (not)", source: "!x" },
547→      { label: "PrefixUnaryExpression (neg)", source: "-x" },
548→      { label: "PrefixUnaryExpression (bitwise_not)", source: "~x" },
549→      { label: "PropertyAccessExpression", source: "x.length" },
550→      { label: "TypeOfExpression", source: "typeof x" },
551→      { label: "CallExpression (method)", source: 'x.indexOf("a")' },
552→      { label: "CallExpression (method no args)", source: "x.trim()" },
553→      { label: "CallExpression (free fn)", source: "parseInt(x)" },
554→      { label: "ParenthesizedExpression", source: "(x)" },
555→    ];
556→
557→    for (const { label, source } of cases) {
558→      const node = parseExpr(source);
559→      const fromExpr = buildSymExpr(node, paramNames);
560→      const fromFlow = buildSymExprWithFlow(node, resolveName);
561→
562→      // Both must return non-unknown for param-involving expressions
563→      if (fromExpr.kind === "unknown") {
564→        throw new Error(`buildSymExpr returned unknown for ${label}: ${source}`);
565→      }
566→      if (fromFlow.kind === "unknown") {
567→        throw new Error(`buildSymExprWithFlow returned unknown for ${label}: ${source}`);
568→      }
569→    }
570→  });
571→
572→  it("both builders return unknown for non-param identifiers", () => {
573→    const node = parseExpr("unknownVar");
574→    const fromExpr = buildSymExpr(node, paramNames);
575→    const fromFlow = buildSymExprWithFlow(node, resolveName);
576→
577→    expect(fromExpr.kind).toBe("unknown");
578→    expect(fromFlow.kind).toBe("unknown");
579→  });
580→
581→  it("nested expressions maintain parity", () => {
582→    const nestedCases = [
583→      'x.length > 0',
584→      'x.indexOf("@") !== -1',
585→      'typeof x === "string"',
586→      '!(x > 0)',
587→      'x + 1 > 0',
588→    ];
589→
590→    for (const source of nestedCases) {
591→      const node = parseExpr(source);
592→      const fromExpr = buildSymExpr(node, paramNames);
593→      const fromFlow = buildSymExprWithFlow(node, resolveName);
594→
595→      if (fromExpr.kind === "unknown") {
596→        throw new Error(`buildSymExpr returned unknown for: ${source}`);
597→      }
598→      if (fromFlow.kind === "unknown") {
599→        throw new Error(`buildSymExprWithFlow returned unknown for: ${source}`);
600→      }
601→    }
602→  });
603→});
