392→/**
393→ * Parse a JSON string into a Request, returning an error response if invalid.
394→ */
395→export function parseRequest(line: string): { request: Request } | { error: ErrorResponse } {
396→  let parsed: unknown;
397→  try {
398→    parsed = JSON.parse(line);
399→  } catch {
400→    return {
401→      error: errorResponse(0, "invalid_request", `Invalid JSON: ${line.slice(0, 100)}`),
402→    };
403→  }
404→
405→  if (typeof parsed !== "object" || parsed === null) {
406→    return {
407→      error: errorResponse(0, "invalid_request", "Request must be a JSON object"),
408→    };
409→  }
410→
411→  const obj = parsed as Record<string, unknown>;
412→
413→  if (typeof obj["id"] !== "number") {
414→    return {
415→      error: errorResponse(0, "invalid_request", "Request must have a numeric 'id' field"),
416→    };
417→  }
418→
419→  const id = obj["id"] as number;
420→
421→  if (typeof obj["protocol_version"] !== "string") {
422→    return {
423→      error: errorResponse(id, "invalid_request", "Request must have a 'protocol_version' string field"),
424→    };
425→  }
426→
427→  if (typeof obj["command"] !== "string") {
428→    return {
429→      error: errorResponse(id, "invalid_request", "Request must have a 'command' string field"),
430→    };
431→  }
432→
433→  const validCommands = ["handshake", "analyze", "instrument", "execute", "setup", "teardown", "generate", "shutdown"];
434→  if (!validCommands.includes(obj["command"] as string)) {
435→    return {
436→      error: errorResponse(id, "invalid_request", `Unknown command: ${String(obj["command"])}`),
437→    };
438→  }
439→
440→  return { request: parsed as Request };
441→}
